import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { ApiService } from 'src/app/shared/services/api.service';
import { ToastService } from 'src/app/shared/services/toast.service';

@Component({
  selector: 'npr-excel-mapping',
  templateUrl: './excel-mapping.component.html',
  styleUrls: ['./excel-mapping.component.scss']
})
export class ExcelMappingComponent implements OnInit {
  excelData: any;
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  isLoading:boolean = false;

  constructor(private apiService:ApiService,private toastService : ToastService,private router : Router ) { }

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [4] } ],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]]
    };
    
    this.getexcelMappingSummary();
  }
  getexcelMappingSummary() {
    this.isLoading = true;
    this.apiService.getMappingSummary().subscribe(data => {
      this.excelData = data;
      this.isLoading = false;

      this.dtTrigger.next();
     
    })
  }
  
  setDataFromSummaryToUpdateExcelMapping(element) {
    console.log("element.extCode",element.extSysCode )
    this.apiService.setexcelSummaryData({
      extCode: element.extSysCode,
      extSysName: element.extSys,
  });
  this.router.navigate(['/excel-mapping/excel-mapping-edit']);

}

}
